object Solution { private class Node(var content: Option[String] = None) { val children = scala.collection.mutable.Map[String, Node](); def isFile: Boolean = content.isDefined }; def run_fs(commands: Seq[Seq[Any]]): Seq[Any] = { val root = new Node(); def parts(path: String): Seq[String] = path.split("/").filter(_.nonEmpty).toSeq; def nodeAt(segs: Seq[String], create: Boolean = false): Option[Node] = { var cur = root; for (seg <- segs) { if (cur.isFile) return None; if (!cur.children.contains(seg)) { if (!create) return None; cur.children(seg) = new Node() }; cur = cur.children(seg) }; Some(cur) }; val out = scala.collection.mutable.ArrayBuffer[Any](); for (cmd <- commands) cmd(0).toString match { case "mkdir" => nodeAt(parts(cmd(1).toString), create = true); case "addFile" => val segs = parts(cmd(1).toString); val parent = nodeAt(segs.dropRight(1), create = true).get; parent.children(segs.last) = new Node(Some(cmd(2).toString)); case "ls" => val segs = parts(cmd(1).toString); val node = nodeAt(segs).get; out += (if (node.isFile) Seq(segs.last) else node.children.keys.toSeq.sorted); case "cat" => out += nodeAt(parts(cmd(1).toString)).get.content.get; case "rm" => val segs = parts(cmd(1).toString); if (segs.nonEmpty) nodeAt(segs.dropRight(1)).foreach(_.children.remove(segs.last)); case _ => () }; out.toSeq } }
